  ('goblin', 'Goblin', 'Small', 'Humanoid', 'goblinoid', 'neutral evil', 15, 7, '30 ft.', 8, 14, 10, 10, 8, 8, '{"Stealth":6}'::jsonb, 'Darkvision 60 ft., passive Perception 9', 'Common, Goblin', 0.25, '[{"name":"Nimble Escape","text":"Goblin can take Disengage or Hide as a bonus action on each of its turns."}]'::jsonb, '[{"name":"Scimitar","text":"Melee Weapon Attack: +4 to hit, 5 (1d6 + 2) slashing."},{"name":"Shortbow","text":"Ranged Weapon Attack: +4 to hit, range 80/320 ft., 5 (1d6 + 2) piercing."}]'::jsonb, 'Core low-CR ambusher used for early encounters and progression.', '["low-cr","humanoid","starter"]'::jsonb, 'Monster Manual', 'MM p.166', true),
