  ('zombie', 'Zombie', 'Medium', 'Undead', null, 'neutral evil', 8, 22, '20 ft.', 13, 6, 16, 3, 6, 5, '{}'::jsonb, 'Darkvision 60 ft., passive Perception 8', 'Understands languages it knew in life but cannot speak', 0.25, '[{"name":"Undead Fortitude","text":"If damage reduces zombie to 0 hp, it makes CON save (DC 5 + damage taken) unless radiant or critical; on success drops to 1 hp instead."}]'::jsonb, '[{"name":"Slam","text":"Melee Weapon Attack: +3 to hit, 4 (1d6 + 1) bludgeoning."}]'::jsonb, 'Slow but durable undead that pressures action economy.', '["undead","low-cr"]'::jsonb, 'Monster Manual', 'MM p.316', true),
